public class EnvironmentCleaner {

	public Environment clean(Environment value, String workingDir, String uri) {
		Environment result = new Environment(value);
		for (PropertySource source : value.getPropertySources()) {
			String name = source.getName().replace(workingDir, "");
			name = name.replace("applicationConfig: [", "");
			name = uri + "/" + name.replace("]", "");
			result.add(new PropertySource(name, clean(source.getSource(), uri)));
		}
		return result;
	}

	protected Map<?, ?> clean(Map<?, ?> source, String uri) {
		for (Map.Entry<?, ?> entry : source.entrySet()) {
			if (entry.getValue() instanceof PropertyValueDescriptor) {
				PropertyValueDescriptor descriptor = (PropertyValueDescriptor) entry.getValue();
				if (!uri.endsWith("/")) {
					uri = uri + "/";
				}
				String updated = descriptor.getOrigin().replace("[", "[" + uri);
				descriptor.setOrigin(updated);
			}
		}
		return source;
	}

}

public class KryoClassMapRegistrar extends AbstractKryoRegistrar {

	private final Map<Integer, Class<?>> registeredClasses;

	public KryoClassMapRegistrar(Map<Integer, Class<?>> kryoRegisteredClasses) {
		this.registeredClasses = new HashMap<>(kryoRegisteredClasses);
	}

	@Override
	public List<Registration> getRegistrations() {
		List<Registration> registrations = new ArrayList<>(this.registeredClasses.size());
		if (!CollectionUtils.isEmpty(this.registeredClasses)) {
			for (Map.Entry<Integer, Class<?>> entry : this.registeredClasses.entrySet()) {
				Class<?> type = entry.getValue();
				registrations.add(new Registration(type, KRYO.getSerializer(type), entry.getKey()));
			}
		}
		return registrations;
	}

}

@SuppressWarnings("removal")
@Deprecated(forRemoval = true)
class UnmodifiableMapDeserializer extends JsonDeserializer<Map<?, ?>> {

	@Override
	public Map<?, ?> deserialize(JsonParser jp, DeserializationContext ctxt) throws IOException {
		ObjectMapper mapper = (ObjectMapper) jp.getCodec();
		JsonNode node = mapper.readTree(jp);

		Map<String, Object> result = new LinkedHashMap<>();
		if (node != null && node.isObject()) {
			Iterable<Map.Entry<String, JsonNode>> fields = node::fields;
			for (Map.Entry<String, JsonNode> field : fields) {
				result.put(field.getKey(), mapper.readValue(field.getValue().traverse(mapper), Object.class));
			}
		}
		return Collections.unmodifiableMap(result);
	}

}

