@RequiredArgsConstructor
class WsCsrfFilter {

  private final CsrfProperties csrfProperties;
  private final WsCsrfTokenRepository tokenRepository;

  void doFilter(HandshakeRequest request) {
    if (csrfProperties.isEnabled() && tokenRepository != null) {
      WsCsrfToken csrfToken = tokenRepository.loadToken(request);
      boolean missingToken = csrfToken == null;
      if (missingToken) {
        csrfToken = tokenRepository.generateToken(request);
        tokenRepository.saveToken(csrfToken, request);
      }

      String actualToken =
          firstElement(request.getParameterMap().get(csrfToken.getParameterName()));
      if (!Objects.equals(csrfToken.getToken(), actualToken)) {
        throw new IllegalStateException(
            "Invalid CSRF Token '"
                + actualToken
                + "' was found on the request parameter '"
                + csrfToken.getParameterName()
                + "'.");
      }
    }
  }
}

@Getter
@Setter
public class CspHeaderFactory extends HeaderFactory {

  public static final String CSP_HEADER = "Content-Security-Policy";
  public static final String CSP_REPORT_ONLY_HEADER = "Content-Security-Policy-Report-Only";

  @JsonProperty("policy")
  private String policy;

  @JsonProperty("reportOnlyPolicy")
  private String reportOnlyPolicy;

  @Override
  protected Map<String, String> buildHeaders() {
    Map<String, String> headers = new HashMap<>();
    if (policy != null && !policy.isEmpty()) {
      headers.put(CSP_HEADER, policy);
    }
    if (reportOnlyPolicy != null && !reportOnlyPolicy.isEmpty()) {
      headers.put(CSP_REPORT_ONLY_HEADER, reportOnlyPolicy);
    }
    return headers;
  }
}

