@Component
public class UsernameHasher {

    private final byte[] salt;
    private final ThreadLocal<MessageDigest> messageDigestThreadLocal;

    @Autowired
    public UsernameHasher(@Value("${nakadi.hasher.salt}") final String salt) {
        this.salt = salt.getBytes(Charsets.UTF_8);
        this.messageDigestThreadLocal = ThreadLocal.withInitial(DigestUtils::getSha256Digest);
    }

    public String hash(final String value) {
        final MessageDigest messageDigest = messageDigestThreadLocal.get();
        messageDigest.reset();
        messageDigest.update(salt);
        messageDigest.update(value.getBytes(Charsets.UTF_8));
        return Hex.encodeHexString(messageDigest.digest());
    }
}

class Log4J2RuntimeHints implements RuntimeHintsRegistrar {

	@Override
	public void registerHints(RuntimeHints hints, @Nullable ClassLoader classLoader) {
		if (ClassUtils.isPresent(Log4J2LoggingSystem.Factory.LOG4J_CORE_CONTEXT_FACTORY, classLoader)) {
			registerLog4j2Hints(hints, classLoader);
		}
	}

	private void registerLog4j2Hints(RuntimeHints hints, @Nullable ClassLoader classLoader) {
		hints.reflection().registerTypeIfPresent(classLoader, Log4J2LoggingSystem.Factory.LOG4J_CORE_CONTEXT_FACTORY);
		// Register default Log4j2 configuration files
		hints.resources().registerPattern("org/springframework/boot/logging/log4j2/log4j2.xml");
		hints.resources().registerPattern("org/springframework/boot/logging/log4j2/log4j2-file.xml");
		hints.resources().registerPattern("log4j2.springboot");
		// Declares the types that Log4j2LoggingSystem checks for existence reflectively.
		hints.reflection().registerTypeIfPresent(classLoader, Log4J2LoggingSystem.LOG4J_BRIDGE_HANDLER);
		hints.reflection().registerTypeIfPresent(classLoader, Log4J2LoggingSystem.LOG4J_LOG_MANAGER);
	}

}

@Slf4j
public class CustomJobFactory extends SimpleJobFactory {
  private final CollectionDAO collectionDAO;
  private final SearchRepository searchRepository;

  public CustomJobFactory(CollectionDAO collectionDAO, SearchRepository searchRepository) {
    super();
    this.collectionDAO = collectionDAO;
    this.searchRepository = searchRepository;
  }

  @Override
  public Job newJob(TriggerFiredBundle bundle, Scheduler Scheduler) throws SchedulerException {
    JobDetail jobDetail = bundle.getJobDetail();
    Class<? extends Job> jobClass = jobDetail.getJobClass();

    try {
      LOG.debug("Producing instance of Job '{}', class={}", jobDetail.getKey(), jobClass.getName());

      return jobClass
          .getDeclaredConstructor(CollectionDAO.class, SearchRepository.class)
          .newInstance(collectionDAO, searchRepository);
    } catch (Exception var7) {
      throw new SchedulerException(
          "Problem instantiating class '" + jobDetail.getJobClass().getName() + "'", var7);
    }
  }
}

public class BoundedListFilter extends ListFilter {

  private final String endName;
  private final String endId;

  public BoundedListFilter(Include include, String endName, String endId) {
    super(include);
    this.endName = endName;
    this.endId = endId;
    addQueryParam("reindexEndName", endName);
    addQueryParam("reindexEndId", endId);
  }

  @Override
  public String getCondition(String tableName) {
    String base = super.getCondition(tableName);
    String nameCol = tableName == null ? "name" : tableName + ".name";
    String idCol = tableName == null ? "id" : tableName + ".id";
    return base
        + String.format(
            " AND (%s < :reindexEndName OR (%s = :reindexEndName AND %s <= :reindexEndId))",
            nameCol, nameCol, idCol);
  }
}

